import logo from './logo.svg';
import './App.css';
import { useState } from 'react';
import { Block,Block_with_input } from './Block';

function App() {
    const col = {
        red: 200,
        blue: 0,
        green: 0,
    }
    const [is_visible, setIs_visible] = useState(True);
    return (
        <div className="App">
            <header className="App-header">
                <Block color_rgb={col} text="正解"></Block>
                <Block_with_input is_visible={True} text="正解"></Block_with_input>
            </header>
        </div>
    );
}

export default App;
